import{_ as o,o as r,c as n,a3 as t}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"86. Working From Home","description":"","frontmatter":{"title":"86. Working From Home","eba":"Biomedical Engineers 2025-2028","topics":["preliminary"]},"headers":[],"relativePath":"ebas/biomedical-engineers/workplace-rights/86-working-from-home.md","filePath":"ebas/biomedical-engineers/workplace-rights/86-working-from-home.md"}'),i={name:"ebas/biomedical-engineers/workplace-rights/86-working-from-home.md"};function a(s,e,m,l,c,p){return r(),n("div",null,[...e[0]||(e[0]=[t('<h1 id="_86-working-from-home" tabindex="-1">86. Working From Home <a class="header-anchor" href="#_86-working-from-home" aria-label="Permalink to &quot;86. Working From Home&quot;">​</a></h1><p><strong>86.1</strong> The Employer recognises there may be mutual benefits for both Employees and the Employer to access home based work. The Employer will maintain a working from home policy that provides Employees with a genuine opportunity to work from home (WFH) where it is reasonable having regard for the circumstances, including:</p><p><strong>(a)</strong> OHS considerations;</p><p><strong>(b)</strong> any current Government directives or recommendations;</p><p><strong>(c)</strong> service delivery requirements.</p><p><strong>86.2</strong> An Employee is entitled to make a request to WFH in accordance with the Employer’s policy.</p><p><strong>86.3</strong> Where an application is made in accordance with the Employer’s policy, such a request will not be unreasonably refused by the Employer. Without limiting subclauses 86.1 or 86.3, an Employer may refuse an Employee’s request to WFH on Reasonable Business Grounds.</p><p><strong>86.4</strong> Nothing in this clause limits the right of an Employee to request a flexible working arrangement under <a href="/eba/ebas/biomedical-engineers/workplace-rights/85-flexible-working-arrangements.html">clause 85</a> of this Agreement.</p>',8)])])}const d=o(i,[["render",a]]);export{h as __pageData,d as default};
